// src/pages/ngo/admin/RegisterPage.jsx
import React, { useState } from 'react';
import { ngoApi } from '../../../services/api';

export default function RegisterNGO() {
  const [form, setForm] = useState({
    userCert: '',
    ngoId: '',
    name: '',
    regNo: '',
    address: '',
    contact: '',
    description: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      const res = await ngoApi.registerNGO(form);
      setMessage(res?.data || 'NGO registered successfully');
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={form.userCert}
            onChange={onChange}
            placeholder="userCert"
            required
          />
        </div>

        <div>
          <label>NGO ID</label>
          <input
            name="ngoId"
            value={form.ngoId}
            onChange={onChange}
            placeholder="ngoId"
            required
          />
        </div>

        <div>
          <label>Name</label>
          <input
            name="name"
            value={form.name}
            onChange={onChange}
            placeholder="name"
            required
          />
        </div>

        <div>
          <label>Reg No</label>
          <input
            name="regNo"
            value={form.regNo}
            onChange={onChange}
            placeholder="regNo"
            required
          />
        </div>

        <div>
          <label>Address</label>
          <input
            name="address"
            value={form.address}
            onChange={onChange}
            placeholder="address"
            required
          />
        </div>

        <div>
          <label>Contact</label>
          <input
            name="contact"
            value={form.contact}
            onChange={onChange}
            placeholder="contact"
            required
          />
        </div>
      </div>

      <div style={{ marginTop: '12px' }}>
        <label>Description</label>
        <textarea
          name="description"
          value={form.description}
          onChange={onChange}
          placeholder="description"
          required
        />
      </div>

      <button type="submit" disabled={loading} style={{ marginTop: '12px', width: '100%' }}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
